// SPDX-License-Identifier: MIT
pragma solidity ^0.8.27;

/// @title  IHederaTokenService — minimal subset of the Hedera HTS precompile at `0x167`.
/// @notice The full canonical interface ships with the `@hashgraph/smart-contracts` npm
///         package; we redeclare only the function selectors and structs we actually
///         use. Everything that doesn't fit our v1 protocol (NFTs, royalty fees, KYC,
///         pause keys, custom fees beyond what we explicitly set, expiry renewal,
///         delete, etc.) is intentionally omitted to keep the audit surface tight.
///
///         All amounts are int64 because the HTS precompile uses int64 internally
///         (Hedera consensus stores supply as a signed 63-bit integer per HIP-15).
///         Solidity wrappers must bounds-check before casting from uint256.
///
///         Function selectors match the official IHederaTokenService.sol byte-for-byte.
///         Reference: https://github.com/hashgraph/hedera-smart-contracts/blob/main/contracts/system-contracts/hedera-token-service/IHederaTokenService.sol
interface IHederaTokenService {
    /// @notice Hedera Token immutable + mutable spec passed to createFungibleToken.
    struct HederaToken {
        string name;
        string symbol;
        address treasury;        // Account that receives all newly-minted supply
        string memo;
        bool tokenSupplyType;    // false = INFINITE; true = FINITE
        int64 maxSupply;         // ignored when tokenSupplyType == false
        bool freezeDefault;      // if true, every account is frozen on association
        TokenKey[] tokenKeys;    // see KeyType bitmask below
        Expiry expiry;           // auto-renew + expiration
    }

    /// @notice Auto-renewal account + period. Set autoRenewAccount = treasury, period
    ///         = 7776000 (90 days) as the conservative default. Hedera will renew
    ///         automatically as long as autoRenewAccount has the HBAR to pay.
    struct Expiry {
        int64 second;            // 0 = use default
        address autoRenewAccount;
        int64 autoRenewPeriod;
    }

    /// @notice Bitmask values from HTS spec for keyType. OR multiple if one key serves
    ///         several roles (we do this for YT — Market is supply + freeze + wipe).
    /// @dev Keys we use: ADMIN=1 (we never set this — immutable), KYC=2, FREEZE=4,
    ///      WIPE=8, SUPPLY=16, FEE_SCHEDULE=32, PAUSE=64. We only ever set 4, 8, 16.
    struct TokenKey {
        uint256 keyType;         // bitmask
        KeyValue key;
    }

    /// @notice Exactly one of these fields is non-default. For our use:
    ///         contractId = address(this) when the supply contract is the key holder.
    struct KeyValue {
        bool inheritAccountKey;
        address contractId;      // ← we use this
        bytes ed25519;
        bytes ECDSA_secp256k1;
        address delegatableContractId;
    }

    /// @notice Create a fungible HTS token. Returns the token's EVM address (long-zero
    ///         alias of the Hedera token ID). Caller pays a network fee in HBAR
    ///         (~1 HBAR mainnet); that HBAR must be attached as msg.value.
    /// @param  token     immutable + mutable spec.
    /// @param  initialTotalSupply minted to the treasury at create time. We always
    ///                            pass 0 — supply is added later via mintToken.
    /// @param  decimals  immutable. Match the underlying asset (per ERC-5115 for SY).
    function createFungibleToken(
        HederaToken memory token,
        int64 initialTotalSupply,
        int32 decimals
    ) external payable returns (int32 responseCode, address tokenAddress);

    /// @notice Mint new units of a fungible token. Newly minted supply lands in the
    ///         token's treasury. To deliver to a non-treasury account, follow with
    ///         transferToken. `newTotalSupply` is the post-mint supply (capped at
    ///         maxSupply if FINITE). `serialNumbers` is empty for fungible mints.
    function mintToken(
        address token,
        int64 amount,
        bytes[] memory metadata        // ignored for fungible; pass empty
    ) external returns (int32 responseCode, int64 newTotalSupply, int64[] memory serialNumbers);

    /// @notice Burn from the TREASURY account only. To burn from a non-treasury
    ///         holder, use wipeTokenAccount instead (requires wipeKey).
    function burnToken(
        address token,
        int64 amount,
        int64[] memory serialNumbers   // ignored for fungible
    ) external returns (int32 responseCode, int64 newTotalSupply);

    /// @notice Force-burn from any holder. Requires wipeKey to be set on the token
    ///         and held by msg.sender. Bypasses freeze state — works on frozen
    ///         accounts. We use this for YT burn during merge / redeemAfterExpiry
    ///         because YT is permanently frozen.
    function wipeTokenAccount(
        address token,
        address account,
        int64 amount
    ) external returns (int32 responseCode);

    /// @notice Atomic A→B token transfer. Both accounts must be associated; both
    ///         must be unfrozen (or token has no freezeKey). Caller must have
    ///         allowance from `sender` (or be `sender`).
    function transferToken(
        address token,
        address sender,
        address recipient,
        int64 amount
    ) external returns (int32 responseCode);

    /// @notice Associate a token with an account, allowing the account to hold
    ///         non-zero balance. Required pre-receive for accounts whose
    ///         maxAutomaticTokenAssociations is 0 (legacy default). HIP-904 made
    ///         contracts auto-associate by default in Hedera Services 0.46+.
    function associateToken(
        address account,
        address token
    ) external returns (int32 responseCode);

    /// @notice Freeze an account for a token. Requires freezeKey. Frozen accounts
    ///         cannot transfer the token via any path except wipe.
    function freezeToken(
        address token,
        address account
    ) external returns (int32 responseCode);

    /// @notice Inverse of freezeToken.
    function unfreezeToken(
        address token,
        address account
    ) external returns (int32 responseCode);

    // ───────────────────── allowance flow ─────────────────────

    /// @notice Set HTS allowance: `spender` can transfer up to `amount` of `token`
    ///         on behalf of msg.sender. Routes through the precompile (the same
    ///         path that `IERC20(htsToken).approve(spender, amount)` takes via the
    ///         token's ERC-20 facade).
    function approve(
        address token,
        address spender,
        uint256 amount
    ) external returns (int32 responseCode);

    /// @notice Read HTS allowance.
    function allowance(
        address token,
        address owner,
        address spender
    ) external view returns (int32 responseCode, uint256 allowance);

    /// @notice Transfer `amount` of `token` from `from` to `to`, consuming
    ///         allowance(from → msg.sender). Distinct from `transferToken` which
    ///         requires msg.sender == from (or has allowance).
    function transferFrom(
        address token,
        address from,
        address to,
        uint256 amount
    ) external returns (int32 responseCode);
}

src/interfaces/IStandardizedYield.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.27;

/// @title  IStandardizedYield — ERC-5115 + Pendle V2 superset (Hedera HTS variant)
/// @notice Strict superset of EIP-5115. Pendle's PT/YT contracts depend on
///         the extensions (`assetInfo`, reward indexes, isValidTokenIn/Out),
///         so we implement the full interface even if downstream consumers
///         only need the base. References:
///           - https://eips.ethereum.org/EIPS/eip-5115
///           - https://github.com/pendle-finance/pendle-core-v2-public/blob/main/contracts/interfaces/IStandardizedYield.sol
/// @dev    On Hedera the SY share is an HTS-native fungible token — not the SYBase
///         contract itself (the contract creates and treasuries the share). Consumers
///         that want IERC20 reads/writes should use `IERC20(sy.shareToken())` against
///         the Hedera ERC-20 facade. Per EIP-5115, share metadata (decimals/symbol)
///         reflects the *underlying asset*, not the share itself.
interface IStandardizedYield {
    /// @notice TOKEN  = the asset is an ordinary ERC-20 with a market price (e.g. HBARX).
    ///         LIQUIDITY = the asset is an LP / pool position whose price has no direct
    ///         market quote (e.g. SaucerSwap V1 LP token). Downstream pricing must use
    ///         a custom oracle, not `assetAddress`.
    enum AssetType { TOKEN, LIQUIDITY }

    // ───────────────────── core deposit/redeem ─────────────────────

    /// @notice Wrap `amountIn` of `tokenIn` and credit shares to `receiver`.
    /// @dev    `tokenIn` MAY be the underlying yield-bearing token, or any token in
    ///         `getTokensIn()`. When wrapping requires a swap, the SY may charge a
    ///         spread; `previewDeposit` returns the user's exact share output.
    function deposit(address receiver, address tokenIn, uint256 amountIn, uint256 minSharesOut)
        external
        payable
        returns (uint256 sharesOut);

    /// @notice Burn `shares` from `msg.sender` and pay out `tokenOut` to `receiver`.
    function redeem(
        address receiver,
        uint256 shares,
        address tokenOut,
        uint256 minTokenOut,
        bool burnFromInternalBalance
    ) external returns (uint256 amountTokenOut);

    // ───────────────────── pricing ────────────────────────────────

    /// @notice 1e18-scaled asset-per-share rate. SHOULD be monotonically non-decreasing
    ///         under normal operation, but real-world LST rates can drop (slashing).
    ///         Adapters that wrap such assets must handle the down-tick path explicitly.
    function exchangeRate() external view returns (uint256 res);

    function previewDeposit(address tokenIn, uint256 amountIn) external view returns (uint256 sharesOut);
    function previewRedeem(address tokenOut, uint256 shares) external view returns (uint256 amountTokenOut);

    function getTokensIn() external view returns (address[] memory);
    function getTokensOut() external view returns (address[] memory);
    function isValidTokenIn(address token) external view returns (bool);
    function isValidTokenOut(address token) external view returns (bool);

    /// @notice Underlying asset descriptor. CRITICAL for downstream PT/YT pricing —
    ///         consumers must check `assetType` before assuming `assetAddress` has a
    ///         market price feed.
    function assetInfo() external view returns (AssetType assetType, address assetAddress, uint8 assetDecimals);

    function yieldToken() external view returns (address);

    /// @notice The HTS-native share token created by the SY contract. Use this with
    ///         `IERC20(...)` for ERC-20-style reads (balanceOf / totalSupply / transfer
    ///         / approve) — the SYBase contract no longer inherits ERC-20 itself.
    function shareToken() external view returns (address);

    // ───────────────────── rewards ────────────────────────────────
    /// @notice Reward tokens distributed to SY holders proportional to their share.
    ///         May be empty (e.g. pure rate-based LSTs that bake rewards into rate).
    function getRewardTokens() external view returns (address[] memory);
    function claimRewards(address user) external returns (uint256[] memory rewardAmounts);
    function accruedRewards(address user) external view returns (uint256[] memory rewardAmounts);
    function rewardIndexesCurrent() external returns (uint256[] memory);
    function rewardIndexesStored() external view returns (uint256[] memory);

    // ───────────────────── events ─────────────────────────────────

    event Deposit(
        address indexed caller,
        address indexed receiver,
        address indexed tokenIn,
        uint256 amountIn,
        uint256 amountSharesOut
    );
    event Redeem(
        address indexed caller,
        address indexed receiver,
        address indexed tokenOut,
        uint256 amountSharesToRedeem,
        uint256 amountTokenOut
    );
    event ClaimRewards(address indexed user, address[] rewardTokens, uint256[] rewardAmounts);
    event ExchangeRateUpdated(uint256 oldRate, uint256 newRate);
}

src/libraries/HtsHelpers.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.27;

import {IHederaTokenService} from "../interfaces/IHederaTokenService.sol";
import {HederaResponseCodes} from "../interfaces/IHederaResponseCodes.sol";

/// @title  HtsHelpers — typed Solidity wrappers around the HTS precompile.
/// @notice Every helper:
///           1. Bounds-checks uint256 inputs before casting to int64 (HTS native width).
///           2. Calls the precompile via the typed interface.
///           3. Reverts with `HtsCallFailed(code)` on any non-SUCCESS response.
///         This pushes ALL "is this safe to mint/transfer" checks into one place.
///
///         The precompile address is `0x167` — a Hedera system contract present on
///         mainnet/testnet/previewnet. NOT simulated by Foundry's revm; unit tests
///         use `vm.etch(0x167, mockBytecode)` to install MockHederaTokenService.
library HtsHelpers {
    address internal constant PRECOMPILE = address(0x167);

    /// @notice HTS amounts are int64. uint256 → int64 cast must not overflow.
    int64 internal constant MAX_AMOUNT = type(int64).max; // 9_223_372_036_854_775_807

    error HtsCallFailed(int32 code);
    error AmountOverflowsInt64(uint256 amount);

    // ───────────────────── safe cast ─────────────────────

    function _toInt64(uint256 amount) private pure returns (int64) {
        if (amount > uint256(uint64(MAX_AMOUNT))) revert AmountOverflowsInt64(amount);
        return int64(uint64(amount));
    }

    function _check(int32 code) private pure {
        if (code != HederaResponseCodes.SUCCESS) revert HtsCallFailed(code);
    }

    // ───────────────────── token creation ─────────────────────

    /// @notice Build a TokenKey entry for a contract-held key. We always pass
    ///         keys this way: the supply / freeze / wipe authority is the contract
    ///         that holds the key, NOT an EOA.
    /// @param  keyType bitmask: 4=FREEZE, 8=WIPE, 16=SUPPLY. OR them for multi-role.
    function makeKey(uint256 keyType, address contractKeyHolder)
        internal
        pure
        returns (IHederaTokenService.TokenKey memory)
    {
        return IHederaTokenService.TokenKey({
            keyType: keyType,
            key: IHederaTokenService.KeyValue({
                inheritAccountKey: false,
                contractId: contractKeyHolder,
                ed25519: bytes(""),
                ECDSA_secp256k1: bytes(""),
                delegatableContractId: address(0)
            })
        });
    }

    /// @notice Wrapper around createFungibleToken that reverts on failure and returns
    ///         the new HTS token address. Caller passes the exact HBAR amount to attach
    ///         to this call (covers the network fee + auto-renew prepay; ~15 HBAR
    ///         mainnet for token + 90d). Critical: when a contract creates multiple
    ///         tokens in one tx (e.g. Market.setTokens for PT/YT/LP), msg.value must
    ///         be split between the calls — sending msg.value to each would drain the
    ///         contract balance on the first call.
    function createFungible(
        IHederaTokenService.HederaToken memory spec,
        int32 decimals,
        uint256 value
    ) internal returns (address htsToken) {
        // initialTotalSupply = 0 always — we mint on demand via mintToken.
        (int32 code, address tokenAddress) =
            IHederaTokenService(PRECOMPILE).createFungibleToken{value: value}(spec, 0, decimals);
        _check(code);
        return tokenAddress;
    }

    // ───────────────────── mint / burn / wipe ─────────────────────

    /// @notice Mint `amount` of `token` to its treasury. Caller must hold the supply
    ///         key (verified by HTS). Returns the new total supply.
    function mintToTreasury(address token, uint256 amount) internal returns (uint256 newTotal) {
        int64 amt = _toInt64(amount);
        (int32 code, int64 newSupply, ) =
            IHederaTokenService(PRECOMPILE).mintToken(token, amt, new bytes[](0));
        _check(code);
        return uint256(uint64(newSupply));
    }

    /// @notice Burn `amount` of `token` from the treasury. Caller must hold the
    ///         supply key. Returns the new total supply.
    function burnFromTreasury(address token, uint256 amount) internal returns (uint256 newTotal) {
        int64 amt = _toInt64(amount);
        (int32 code, int64 newSupply) =
            IHederaTokenService(PRECOMPILE).burnToken(token, amt, new int64[](0));
        _check(code);
        return uint256(uint64(newSupply));
    }

    /// @notice Force-burn `amount` of `token` from a specific account. Caller must
    ///         hold the wipe key. Bypasses freeze state — works on frozen accounts
    ///         (this is why YT uses wipe for merge/redeem instead of burn).
    function wipeFrom(address token, address account, uint256 amount) internal {
        int64 amt = _toInt64(amount);
        int32 code = IHederaTokenService(PRECOMPILE).wipeTokenAccount(token, account, amt);
        _check(code);
    }

    // ───────────────────── transfer ─────────────────────

    /// @notice Transfer `amount` of `token` from `from` to `to`. Both accounts must
    ///         be associated and unfrozen. Caller must equal `from` OR have HTS
    ///         allowance from `from`.
    function transfer(address token, address from, address to, uint256 amount) internal {
        int64 amt = _toInt64(amount);
        int32 code = IHederaTokenService(PRECOMPILE).transferToken(token, from, to, amt);
        _check(code);
    }

    // ───────────────────── association ─────────────────────

    function associate(address account, address token) internal {
        int32 code = IHederaTokenService(PRECOMPILE).associateToken(account, token);
        _check(code);
    }

    /// @notice Same as `associate` but tolerates already-associated state (response
    ///         code 194 = TOKEN_ALREADY_ASSOCIATED_TO_ACCOUNT). Use in idempotent
    ///         init paths where the same call may be replayed (e.g. setTokens after
    ///         a partial revert).
    function associateIfNeeded(address account, address token) internal {
        int32 code = IHederaTokenService(PRECOMPILE).associateToken(account, token);
        // 22 = SUCCESS, 194 = TOKEN_ALREADY_ASSOCIATED_TO_ACCOUNT (treat as success).
        if (code != HederaResponseCodes.SUCCESS && code != int32(194)) {
            revert HtsCallFailed(code);
        }
    }

    // ───────────────────── freeze / unfreeze ─────────────────────

    function freeze(address token, address account) internal {
        int32 code = IHederaTokenService(PRECOMPILE).freezeToken(token, account);
        _check(code);
    }

    function unfreeze(address token, address account) internal {
        int32 code = IHederaTokenService(PRECOMPILE).unfreezeToken(token, account);
        _check(code);
    }

    /// @notice Atomic unfreeze → transfer → freeze. Used by Market.transferYT and
    ///         by mint-to-frozen-user paths. The 3 ops MUST be in the same tx; if
    ///         any reverts, the whole tx unwinds and the freeze state is preserved.
    function transferThroughFreeze(
        address token,
        address from,
        address to,
        uint256 amount
    ) internal {
        unfreeze(token, from);
        unfreeze(token, to);
        transfer(token, from, to, amount);
        freeze(token, from);
        freeze(token, to);
    }

    // ───────────────────── allowance ─────────────────────

    function approve(address token, address spender, uint256 amount) internal {
        int32 code = IHederaTokenService(PRECOMPILE).approve(token, spender, amount);
        _check(code);
    }

    /// @notice Pull `amount` of `token` from `from` to `to`, using msg.sender's
    ///         allowance from `from`. The allowance MUST have been granted prior
    ///         via `approve` (either directly to the precompile or through the
    ///         token's ERC-20 facade — both route to the same allowance store).
    function transferFrom(address token, address from, address to, uint256 amount) internal {
        int32 code = IHederaTokenService(PRECOMPILE).transferFrom(token, from, to, amount);
        _check(code);
    }
}

src/libraries/MarketMath.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.27;

import {PMath} from "./PMath.sol";

/// @title MarketMath — Pendle V2 logit-curve AMM math, faithful port.
/// @author Fission Protocol contributors. Math design © Pendle Labs;
///         see https://github.com/pendle-finance/pendle-core-v2-public —
///         in particular `contracts/core/Market/MarketMathCore.sol`.
/// @notice The pool persists `lastLnImpliedRate` between trades. On each swap
///         a `rateAnchor` is recomputed from `(lastLnImpliedRate, current
///         proportion)`, so the curve **anchors** to the most recent trade and
///         does not drift purely from time decay between blocks. The new
///         post-trade implied rate is written back to `lastLnImpliedRate`.
/// @dev    Sign convention follows Pendle: positive `netPtToAccount` means the
///         user is *buying* PT (paying SY); negative means *selling* PT
///         (receiving SY). All amounts are denominated in 1e18-scaled units.
///         Asset-side values use the SY's `exchangeRate` as the conversion factor.
library MarketMath {
    using PMath for int256;
    using PMath for uint256;

    // ───────────────────── constants ─────────────────────

    int256 internal constant IONE = 1e18;
    uint256 internal constant ONE = 1e18;

    /// @notice Reference timeframe for implied-rate scaling. Pendle uses 365 days exactly.
    uint256 internal constant IMPLIED_RATE_TIME = 365 days;

    /// @notice PT proportion ceiling — above this the curve becomes unstable.
    int256 internal constant MAX_MARKET_PROPORTION = 0.96e18;

    /// @notice Minimum LP burned to address(1) at pool init (donation-attack defence).
    uint256 internal constant MINIMUM_LIQUIDITY = 1_000;

    /// @notice Maximum allowed `lnFeeRateRoot` ≈ ln(1.05) — caps governance fee at ~5 % per
    ///         year-equivalent. Stops a malicious / mistaken governance from setting fees that
    ///         move price by orders of magnitude.
    int256 internal constant MAX_LN_FEE_RATE_ROOT = 0.05e18;

    // ───────────────────── errors ─────────────────────

    error MarketExpired();
    error MarketProportionMustNotEqualOne();
    error MarketProportionTooHigh();
    error MarketRateScalarBelowZero();
    error MarketExchangeRateBelowOne();
    error InsufficientLiquidity();
    error InvalidLnFeeRateRoot();

    // ───────────────────── types ─────────────────────

    /// @notice Persisted per-market AMM state.
    struct MarketState {
        int256  totalPt;              // PT held by the market
        int256  totalSy;              // SY held by the market
        int256  totalLp;              // LP token total supply
        uint256 expiry;               // immutable (set at market creation)
        int256  scalarRoot;           // immutable (set at market creation)
        int256  lnFeeRateRoot;        // governance, capped by MAX_LN_FEE_RATE_ROOT
        uint256 reserveFeePercent;    // 0..100, % of fees diverted to treasury
        int256  lastLnImpliedRate;    // ← persistent anchor; updated after every trade
    }

    /// @notice Cached values derived from MarketState + SY index at the start of a trade.
    struct PreCompute {
        int256 rateScalar;
        int256 totalAsset;            // = totalSy * syIndex / 1e18
        int256 rateAnchor;
        int256 feeRate;               // multiplicative fee on the exchange rate
    }

    // ───────────────────── pre-trade compute ─────────────────────

    /// @notice Compute `(rateScalar, totalAsset, rateAnchor, feeRate)` for the current state.
    /// @param market  current persisted market state
    /// @param syIndex SY exchange rate (1e18-scaled), supplied by caller
    /// @param now_    current block timestamp
    function getMarketPreCompute(MarketState memory market, int256 syIndex, uint256 now_)
        internal
        pure
        returns (PreCompute memory pre)
    {
        if (now_ >= market.expiry) revert MarketExpired();
        uint256 ttx = market.expiry - now_;

        pre.rateScalar = _getRateScalar(market.scalarRoot, ttx);
        /// BinaryOpMutation(`/` |==> `+`) of: `pre.totalAsset = (market.totalSy * syIndex) / IONE;`
        pre.totalAsset = (market.totalSy * syIndex)+IONE;
        pre.rateAnchor = _getRateAnchor(market.totalPt, market.lastLnImpliedRate, pre.totalAsset, pre.rateScalar, ttx);
        pre.feeRate = _getExchangeRateFromImpliedRate(market.lnFeeRateRoot, ttx);
    }

    /// @notice rateScalar(t) = scalarRoot · IMPLIED_RATE_TIME / t.
    /// @dev    Curve gets *steeper* as expiry approaches — small proportion changes
    ///         at maturity move implied rate less in absolute terms.
    function _getRateScalar(int256 scalarRoot, uint256 ttx) private pure returns (int256 r) {
        r = (scalarRoot * int256(IMPLIED_RATE_TIME)) / int256(ttx);
        if (r <= 0) revert MarketRateScalarBelowZero();
    }

    /// @notice Recover the rate anchor that produces `lastLnImpliedRate` at the *current* proportion.
    function _getRateAnchor(
        int256 totalPt,
        int256 lastLnImpliedRate,
        int256 totalAsset,
        int256 rateScalar,
        uint256 ttx
    ) private pure returns (int256 rateAnchor) {
        int256 newExchangeRate = _getExchangeRateFromImpliedRate(lastLnImpliedRate, ttx);
        if (newExchangeRate < IONE) revert MarketExchangeRateBelowOne();

        int256 proportion = totalPt.divWadInt(totalPt + totalAsset);
        int256 lnProportion = _logProportion(proportion);
        rateAnchor = newExchangeRate - lnProportion.divWadInt(rateScalar);
    }

    /// @notice exchangeRate(impliedRate, t) = exp(lnImpliedRate · t / YEAR).
    function _getExchangeRateFromImpliedRate(int256 lnImpliedRate, uint256 ttx)
        private
        pure
        returns (int256)
    {
        int256 rt = (lnImpliedRate * int256(ttx)) / int256(IMPLIED_RATE_TIME);
        return PMath.expWad(rt);
    }

    /// @notice Inverse: extract lnImpliedRate from a post-trade exchange rate.
    function _getLnImpliedRate(int256 exchangeRate, uint256 ttx) private pure returns (int256) {
        int256 lnRate = PMath.lnWad(exchangeRate);
        return (lnRate * int256(IMPLIED_RATE_TIME)) / int256(ttx);
    }

    /// @notice ln(p / (1−p)) — the logit transform of `proportion`.
    function _logProportion(int256 proportion) private pure returns (int256) {
        if (proportion == IONE) revert MarketProportionMustNotEqualOne();
        int256 logitP = proportion.divWadInt(IONE - proportion);
        return PMath.lnWad(logitP);
    }

    // ───────────────────── execute trade ─────────────────────

    /// @notice Compute the SY amounts for a trade of `netPtToAccount` PT, and produce the
    ///         updated `lastLnImpliedRate` for persistence.
    /// @param market           current state (read-only — caller persists the new state)
    /// @param pre              cached pre-compute for this block
    /// @param netPtToAccount   positive ⇒ user buys PT (pays SY); negative ⇒ user sells PT
    /// @return netSyToAccount  positive ⇒ user receives SY; negative ⇒ user pays SY
    /// @return netSyFee        total fee in SY (always positive)
    /// @return netSyToReserve  reserve fee in SY (always positive, ≤ netSyFee)
    /// @return newLnImpliedRate post-trade lnImpliedRate to persist on the market
    function executeTradeCore(MarketState memory market, PreCompute memory pre, int256 netPtToAccount, uint256 now_)
        internal
        pure
        returns (int256 netSyToAccount, int256 netSyFee, int256 netSyToReserve, int256 newLnImpliedRate)
    {
        if (now_ >= market.expiry) revert MarketExpired();
        uint256 ttx = market.expiry - now_;

        int256 newPt = market.totalPt - netPtToAccount;
        if (newPt <= 0) revert InsufficientLiquidity();

        int256 proportion = newPt.divWadInt(newPt + pre.totalAsset);
        if (proportion > MAX_MARKET_PROPORTION) revert MarketProportionTooHigh();

        int256 preFeeExchangeRate = _logProportion(proportion).divWadInt(pre.rateScalar) + pre.rateAnchor;
        if (preFeeExchangeRate < IONE) revert MarketExchangeRateBelowOne();

        // Asset-denominated amount user receives or pays before fee. Sign mirrors `-netPtToAccount`.
        int256 preFeeAssetToAccount = (-netPtToAccount).divWadInt(preFeeExchangeRate);

        int256 postFeeAssetToAccount;
        int256 postFeeExchangeRate;

        if (netPtToAccount > 0) {
            // User is buying PT (paying SY). Charge by *raising* the effective rate
            //   ⇒ user pays MORE asset. postRate = preRate / feeRate (feeRate < 1e18 here? No —
            //   feeRate = exp(lnFeeRateRoot · IMPLIED_RATE_TIME / t), with lnFeeRateRoot > 0,
            //   so feeRate > 1e18; therefore preRate / feeRate < preRate).
            // The Pendle convention: postFeeExchangeRate = preFeeExchangeRate / feeRate when buying.
            postFeeExchangeRate = preFeeExchangeRate.divWadInt(pre.feeRate);
            if (postFeeExchangeRate < IONE) revert MarketExchangeRateBelowOne();
            postFeeAssetToAccount = (-netPtToAccount).divWadInt(postFeeExchangeRate);
        } else {
            // User is selling PT (receiving SY). postFeeExchangeRate = preFeeExchangeRate * feeRate
            //   ⇒ effective rate higher ⇒ same PT yields LESS SY back.
            postFeeExchangeRate = preFeeExchangeRate.mulWadInt(pre.feeRate);
            postFeeAssetToAccount = (-netPtToAccount).divWadInt(postFeeExchangeRate);
        }

        // Asset-side fee = preFeeAssetToAccount − postFeeAssetToAccount, always positive in
        // absolute terms. We compute as |fee| and convert to SY using `pre.totalAsset` ratio.
        int256 feeAsset = _abs(preFeeAssetToAccount - postFeeAssetToAccount);

        // Convert asset → SY:  syAmount = assetAmount * totalSy / totalAsset.
        // (For non-zero totalAsset; reverts upstream if totalAsset == 0 due to divWadInt below.)
        netSyToAccount = (postFeeAssetToAccount * market.totalSy) / pre.totalAsset;
        netSyFee = (feeAsset * market.totalSy) / pre.totalAsset;
        netSyToReserve = (netSyFee * int256(market.reserveFeePercent)) / 100;

        newLnImpliedRate = _getLnImpliedRate(postFeeExchangeRate, ttx);
    }

    // ───────────────────── add / remove liquidity ─────────────────────

    /// @notice Proportional liquidity add — does NOT move `lastLnImpliedRate`.
    function addLiquidityCore(MarketState memory market, int256 syDesired, int256 ptDesired)
        internal
        pure
        returns (int256 netLpToAccount, int256 syUsed, int256 ptUsed, int256 netSyToReserve)
    {
        if (syDesired <= 0 || ptDesired <= 0) revert InsufficientLiquidity();
        // M-4 audit fix: cap inputs at int128 max so the first-add `syDesired * ptDesired`
        // multiplication can't overflow uint256 (each factor fits in 128 bits → product
        // fits in 256). Practical Pendle markets never seed beyond this; the guard is
        // pure safety.
        if (syDesired > type(int128).max || ptDesired > type(int128).max) revert InsufficientLiquidity();

        if (market.totalLp == 0) {
            // First-add: LP = sqrt(syDesired · ptDesired) − MINIMUM_LIQUIDITY
            uint256 product = uint256(syDesired) * uint256(ptDesired);
            uint256 sqrtL = PMath.sqrt(product);
            if (sqrtL <= MINIMUM_LIQUIDITY) revert InsufficientLiquidity();
            netLpToAccount = int256(sqrtL - MINIMUM_LIQUIDITY);
            syUsed = syDesired;
            ptUsed = ptDesired;
        } else {
            // Subsequent: take min ratio. Caller is expected to refund unused side or revert.
            int256 lpFromSy = (syDesired * market.totalLp) / market.totalSy;
            int256 lpFromPt = (ptDesired * market.totalLp) / market.totalPt;
            if (lpFromSy < lpFromPt) {
                netLpToAccount = lpFromSy;
                syUsed = syDesired;
                ptUsed = (lpFromSy * market.totalPt) / market.totalLp;
            } else {
                netLpToAccount = lpFromPt;
                ptUsed = ptDesired;
                syUsed = (lpFromPt * market.totalSy) / market.totalLp;
            }
        }
        if (netLpToAccount <= 0) revert InsufficientLiquidity();
        netSyToReserve = 0;
    }

    /// @notice Proportional liquidity remove — does NOT move `lastLnImpliedRate`.
    function removeLiquidityCore(MarketState memory market, int256 lpToRemove)
        internal
        pure
        returns (int256 netSyToAccount, int256 netPtToAccount)
    {
        if (lpToRemove <= 0 || lpToRemove > market.totalLp) revert InsufficientLiquidity();
        netSyToAccount = (lpToRemove * market.totalSy) / market.totalLp;
        netPtToAccount = (lpToRemove * market.totalPt) / market.totalLp;
    }

    // ───────────────────── helpers ─────────────────────

    function _abs(int256 x) private pure returns (int256) {
        return x < 0 ? -x : x;
    }

    /// @notice Computes the initial `lastLnImpliedRate` for a freshly initialised market.
    /// @dev    Caller supplies the desired starting implied rate (the "seeded" yield curve).
    function setInitialLnImpliedRate(
        MarketState memory market,
        int256 syIndex,
        int256 initialAnchor,
        uint256 now_
    ) internal pure returns (int256 lnImpliedRate) {
        if (now_ >= market.expiry) revert MarketExpired();
        uint256 ttx = market.expiry - now_;

        int256 totalAsset = (market.totalSy * syIndex) / IONE;
        int256 proportion = market.totalPt.divWadInt(market.totalPt + totalAsset);

        int256 rateScalar = _getRateScalar(market.scalarRoot, ttx);
        int256 lnProp = _logProportion(proportion);
        int256 exchangeRate = lnProp.divWadInt(rateScalar) + initialAnchor;
        if (exchangeRate < IONE) revert MarketExchangeRateBelowOne();

        lnImpliedRate = _getLnImpliedRate(exchangeRate, ttx);
    }

    /// @notice Sanity check the governance-set `lnFeeRateRoot`.
    function validateLnFeeRateRoot(int256 lnFeeRateRoot) internal pure {
        if (lnFeeRateRoot < 0 || lnFeeRateRoot > MAX_LN_FEE_RATE_ROOT) {
            revert InvalidLnFeeRateRoot();
        }
    }
}

